package com.schoolbus.controller;
import com.schoolbus.dto.request.*;import com.schoolbus.dto.response.*;import com.schoolbus.service.AdminCrudService;import jakarta.validation.Valid;import org.springframework.data.domain.*;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/admin/buses") public class AdminBusController{private final AdminCrudService s;public AdminBusController(AdminCrudService s){this.s=s;}@GetMapping public ApiResponse<PageResponse<BusResponse>> list(@RequestParam(required=false)String search,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.success(PageResponse.from(s.buses(search,PageRequest.of(page,size))));}@GetMapping("/{id}")public ApiResponse<BusResponse> get(@PathVariable Long id){return ApiResponse.success(s.bus(id));}@PostMapping public ResponseEntity<ApiResponse<BusResponse>> create(@Valid @RequestBody BusRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success("Bus created",s.createBus(r)));}@PutMapping("/{id}")public ApiResponse<BusResponse> update(@PathVariable Long id,@Valid @RequestBody BusRequest r){return ApiResponse.success(s.updateBus(id,r));}@PatchMapping("/{id}/deactivate")public ApiResponse<Void> deactivate(@PathVariable Long id){s.deactivateBus(id);return ApiResponse.success("Bus deactivated",null);}}
